1	export type Cell = boolean;
2	export type Grid = Cell[][];
3	
4	const countNeighbors = (grid: Grid, row: number, col: number): number => {
5	  let count = 0;
6	  for (let r = row - 1; r <= row + 1; r++) {
7	    for (let c = col - 1; c <= col + 1; c++) {
8	      if (r === row && c === col) continue;
9	      if (r >= 0 && r < grid.length && c >= 0 && c < grid[0].length && grid[r][c]) {
10	        count++;
11	      }
12	    }
13	  }
14	  return count;
15	};
16	
17	const shouldCellBeAlive = (isAlive: boolean, neighbors: number): boolean =>
18	  (isAlive && (neighbors === 2 || neighbors === 3)) ||
19	  (!isAlive && neighbors === 3);
20	
21	export function nextGeneration(grid: Grid): Grid {
22	  if (grid.length === 0) {
23	    return [];
24	  }
25	
26	  return grid.map((row, rowIdx) =>
27	    row.map((cell, colIdx) => {
28	      const neighbors = countNeighbors(grid, rowIdx, colIdx);
29	      return shouldCellBeAlive(cell, neighbors);
30	    })
31	  );
32	}
